def tier(min_qty: int, max_qty: int | None, unit_price: float, lead_time_days: int) -> dict:
    return {
        "min_qty": min_qty,
        "max_qty": max_qty,
        "unit_price_usd": money(unit_price),
        "lead_time_days": lead_time_days,
        "lead_time_weeks": round(lead_time_days / 7, 2),
    }


