def freight_quote(
    freight_id: str,
    quote_id: str,
    mode: str,
    cost: float,
    transit_days: tuple[int, int],
    valid_until: str,
    route_risk: str,
    forwarder: str,
    weight_kg: float,
    cbm: float,
    *,
    cold_chain_support: bool = False,
    status: str = "active",
    risk_notes: str = "",
    origin: str = "Dubai free zone",
    destination: str = "",
) -> dict:
    return {
        "id": freight_id,
        "quote_id": quote_id,
        "mode": mode,
        "forwarder": forwarder,
        "cost_usd": money(cost),
        "currency": "USD",
        "transit_days_min": transit_days[0],
        "transit_days_max": transit_days[1],
        "transit_days_text": f"{transit_days[0]}-{transit_days[1]} days",
        "valid_until": valid_until,
        "route_risk": route_risk,
        "risk_notes": risk_notes,
        "cold_chain_support": cold_chain_support,
        "shipment_weight_kg": money(weight_kg),
        "shipment_cbm": money(cbm),
        "status": status,
        "origin": origin,
        "destination": destination,
        "quote_date": "2026-06-01",
    }


