def invoice(
    invoice_id: str,
    opportunity_id: str,
    customer_id: str,
    phase_id: str,
    phase_name: str,
    amount: float,
    issue_date: str,
    due_date: str,
    status: str,
    paid_amount: float,
) -> dict:
    return {
        "id": invoice_id,
        "invoice_number": invoice_id.replace("INV-", "MBI-"),
        "opportunity_id": opportunity_id,
        "customer_id": customer_id,
        "phase_id": phase_id,
        "phase_name": phase_name,
        "issue_date": issue_date,
        "due_date": due_date,
        "amount_usd": money(amount),
        "paid_amount_usd": money(paid_amount),
        "outstanding_amount_usd": money(amount - paid_amount),
        "status": status,
        "billing_type": "milestone_service",
    }


